import { BadRequestException, Injectable } from '@nestjs/common';

import { TransactionHost } from '@nestjs-cls/transactional';

import { TransactionalAdapterTypeOrm } from '@/modules/global';
import { FileEntity, TicketCategory, TicketEntity } from '@/db';
import { NotificationMedia } from '@/modules/notification';
import { EmailNotificationService } from '@/modules/notification';

@Injectable()
export class GuestTicketService {
  constructor(
    private readonly txHost: TransactionHost<TransactionalAdapterTypeOrm>,
    private readonly emailNotificationService: EmailNotificationService,
  ) {}

  async create(dto: {
    fullName: string;
    email: string;
    category: TicketCategory;
    description: string;
    attachedFileIds: string[];
    preferredContactMethods: NotificationMedia[];
  }) {
    return this.txHost.withTransaction(async () => {
      const ticketRepository = this.txHost.tx.getRepository(TicketEntity);
      const fileRepository = this.txHost.tx.getRepository(FileEntity);

      if (dto.attachedFileIds.length > 0) {
        const files = await fileRepository.findBy(
          dto.attachedFileIds.map((id) => ({ id })),
        );

        if (files.length !== dto.attachedFileIds.length) {
          throw new BadRequestException('One or more attached files not found');
        }

        const invalidFiles = files.filter(
          (f) => !f.path.startsWith('/guest-uploads/'),
        );
        if (invalidFiles.length > 0) {
          throw new BadRequestException('Invalid file IDs provided');
        }
      }

      const ticket = await ticketRepository.save({
        userId: null,
        isGuest: true,
        guestName: dto.fullName,
        guestEmail: dto.email,
        subject: `Guest: ${dto.fullName}`,
        description: dto.description,
        category: dto.category,
        attachedFiles: dto.attachedFileIds.map((id) => ({ id })),
        preferredContactMethods: dto.preferredContactMethods,
      });

      await this.emailNotificationService.sendGuestTicketConfirmation({
        to: dto.email,
        guestName: dto.fullName,
        ticketId: ticket.id,
        category: dto.category,
        description: dto.description,
      });

      return ticket;
    });
  }
}

